const body = $input.first().json.body || $input.first().json;
const { file_data, mime_type, filename } = body;

if (!file_data) {
  throw new Error('No file_data provided');
}

const buffer = Buffer.from(file_data, 'base64');
const binary = await this.helpers.prepareBinaryData(
  buffer,
  filename || 'payslip.pdf',
  mime_type || 'application/pdf'
);

return {
  json: { filename, mime_type },
  binary: { data: binary }
};

const response = $input.first().json;

let text = response.output || response.text || '';

if (!text && response.content && response.content.parts && response.content.parts[0]) {
  text = response.content.parts[0].text || '';
}

if (typeof text === 'object') text = JSON.stringify(text);
text = String(text).trim();

text = text.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '').trim();

const firstBrace = text.indexOf('{');
if (firstBrace > 0) text = text.substring(firstBrace);
const lastBrace = text.lastIndexOf('}');
if (lastBrace > 0) text = text.substring(0, lastBrace + 1);

let data;
try {
  data = JSON.parse(text);
} catch (e) {
  return [{ json: { success: false, error: 'Failed to parse JSON: ' + e.message, data: null } }];
}

function parseAmt(val) {
  if (val === null || val === undefined) return null;
  if (typeof val === 'string') val = val.replace(/[^0-9.-]/g, '');
  if (val === '') return null;
  return parseFloat(Number(val).toFixed(2));
}

function parseArr(val) {
  if (!Array.isArray(val)) return null;
  return val.map(v => ({ name: v.name || '', amount: parseAmt(v.amount) || 0 }));
}

return [{ json: {
  success: true,
  data: {
    employer_name: data.employer_name || null,
    employer_tax_ref: data.employer_tax_ref || null,
    employee_number: data.employee_number || null,
    tax_number: data.tax_number || null,
    id_number: data.id_number || null,
    irp5_reference: data.irp5_reference || null,
    pay_period: data.pay_period || null,
    designation: data.designation || null,
    cost_centre: data.cost_centre || null,
    hourly_rate: parseAmt(data.hourly_rate),
    normal_hours: parseAmt(data.normal_hours),
    leave_days: parseAmt(data.leave_days),
    gross_salary: parseAmt(data.gross_salary),
    net_salary: parseAmt(data.net_salary),
    bonus: parseAmt(data.bonus),
    commission: parseAmt(data.commission),
    overtime: parseAmt(data.overtime),
    travel_allowance: parseAmt(data.travel_allowance),
    other_earnings: parseArr(data.other_earnings),
    paye: parseAmt(data.paye),
    uif: parseAmt(data.uif),
    medical_aid: parseAmt(data.medical_aid),
    medical_aid_members: data.medical_aid_members != null ? parseInt(data.medical_aid_members) : null,
    pension_fund: parseAmt(data.pension_fund),
    retirement_annuity: parseAmt(data.retirement_annuity),
    sdl: parseAmt(data.sdl),
    wellness_fund: parseAmt(data.wellness_fund),
    union_fees: parseAmt(data.union_fees),
    other_deductions: parseArr(data.other_deductions),
    total_deductions: parseAmt(data.total_deductions),
    employer_pension: parseAmt(data.employer_pension),
    employer_uif: parseAmt(data.employer_uif),
    employer_oid: parseAmt(data.employer_oid),
    ytd_gross: parseAmt(data.ytd_gross),
    ytd_paye: parseAmt(data.ytd_paye),
    ytd_pension: parseAmt(data.ytd_pension),
    ytd_medical_aid: parseAmt(data.ytd_medical_aid),
    notes: data.notes || null,
    confidence: data.confidence ?? null
  }
}}];
